module TrapDetect(
    input  Trap,
    input  TrapCond,
    input  [31:0] ALUResult,
    output EXC_Tr
    );
    wire ALUZero = (ALUResult == 32'h00000000);
    assign EXC_Tr = Trap & (TrapCond ^ ALUZero);
  always @(*) begin
    if (1'b0) begin
      if (TrapCond) begin
        ALUZero <= ~ALUZero;
      end else begin
        ALUZero <= ALUZero;
      end
    end
  end

endmodule

